air[1]; chaps.forEach(function(c, i) { html += '<div class="diag-item"><div class="diag-title-row"><span>第' + parts[0] + '章 ' + escapeHtml(parts[1]) + '</span><span class="diag-title-sub">行' + (c.lineIndex + 1) + '</span></div><span class="badge ' + (i === 0 ? 'badge-green' : 'badge-red') + '">' + (i === 0 ? '保留' : '重复') + '</span></div>'; }); }); } html += '</div>'; html += '<div class="diag-section"><h4>同号不同标题 (' + v.sameNumDiffTitleCount + '组)</h4>'; html += '<div style="font-size:12px; color:var(--text-secondary); margin-bottom:10px;">章节号相同但标题不同，非严格重复，建议排序后手动检查</div>'; if (v.sameNumDiffTitleCount === 0) { html += '<div class="empty-state">无同号不同标题。</div>'; } else { Object.entries(v.sameNumDiffTitleMap).forEach(function(pair) { var num = pair[0]; var chaps = pair[1]; chaps.forEach(function(c) { html += '<div class="diag-item"><div class="diag-title-row"><span>第' + num + '章 ' + escapeHtml(c.chapterTitle) + '</span><span class="diag-title-sub">行' + (c.lineIndex + 1) + '</span></div><span class="badge badge-blue">同号异题</span></div>'; }); }); } html += '</div>'; html += '<div class="diag-section"><h4>疑似章节 (' + v.suspectedCount + '个)</h4>'; html += '<div style="font-size:12px; color:var(--text-secondary); margin-bottom:10px;">识别规则：行中包含【第】【章】【阿拉伯数字】【空格】中至少3个要素，但非正式章节</div>'; if (v.suspectedCount === 0) { html += '<div class="empty-state">无疑似章节。</div>'; } else { State.chapters.filter(function(c) { return c.type === 'suspected'; }).forEach(function(c) { var elements = []; if (c.originalText.includes('第')) elements.push('第'); if (c.originalText.includes('章')) elements.push('章'); if (/\d+/.test(c.originalText)) elements.push('阿拉伯数字'); if (/\s/.test(c.originalText)) elements.push('空格'); html += '<div class="diag-item" style="flex-direction:column; align-items:flex-start;">'; html += '<div style="width:100%; font-size:13px; margin-bottom:4px;">' + escapeHtml(c.originalText) + '</div>'; html += '<div style="font-size:11px; color:var(--text-secondary);">行' + (c.lineIndex + 1) + ' | 命中要素: ' + elements.join('、') + '</div>'; html += '</div>'; }); } html += '</div>'; container.innerHTML = html; } /* ===== 自定义拖动滚动条 ===== */ var scrollDrag = { active: false, startY: 0, startThumbTop: 0 }; (function() { var thumb = document.getElementById('scrollbar-thumb'); thumb.addEventListener('mousedown', onThumbStart); thumb.addEventListener('touchstart', onThumbStart, { passive: false }); })(); function onThumbStart(e) { e.preventDefault(); e.stopPropagation(); scrollDrag.active = true; var touch = e.touches ? e.touches[0] : e; scrollDrag.startY = touch.clientY; scrollDrag.startThumbTop = parseFloat(document.getElementById('scrollbar-thumb').style.top) || 0; document.getElementById('scrollbar-thumb').classList.add('active'); document.addEventListener('mousemove', onThumbMove); document.addEventListener('mouseup', onThumbEnd); document.addEventListener('touchmove', onThumbMove, { passive: false }); document.addEventListener('touchend', onThumbEnd); } function onThumbMove(e) { if (!scrollDrag.active) return; e.preventDefault(); var touch = e.touches ? e.touches[0] : e; var deltaY = touch.clientY - scrollDrag.startY; var track = document.getElementById('scrollbar-track'); var thumb = document.getElementById('scrollbar-thumb'); var container = document.getElementById('list-container'); var inner = document.getElementById('list-inner'); var totalHeight = parseInt(inner.style.height) || 0; var viewHeight = container.clientHeight; var trackHeight = track.clientHeight; var thumbHeight = parseFloat(thumb.style.height) || 30; var maxThumbTop = trackHeight - thumbHeight; var maxScroll = totalHeight - viewHeight; if (maxScroll <= 0) return; var newThumbTop = Math.max(0, Math.min(maxThumbTop, scrollDrag.startThumbTop + deltaY)); thumb.style.top = newThumbTop + 'px'; container.scrollTop = (newThumbTop / maxThumbTop) * maxScroll; } function onThumbEnd() { scrollDrag.active = false; document.getElementById('scrollbar-thumb').classList.remove('active'); document.removeEventListener('mousemove', onThumbMove); document.removeEventListener('mouseup', onThumbEnd); document.removeEventListener('touchmove', onThumbMove); document.removeEventListener('touchend', onThumbEnd); } function updateScrollbar() { var container = document.getElementById('list-container'); var inner = document.getElementById('list-inner'); var track = document.getElementById('scrollbar-track'); var thumb = document.getElementById('scrollbar-thumb'); var totalHeight = parseInt(inner.style.height) || 0; var viewHeight = container.clientHeight; if (totalHeight <= viewHeight || viewHeight <= 0) { track.style.display = 'none'; return; } track.style.display = 'block'; var trackHeight = track.clientHeight; var thumbHeight = Math.max(30, (viewHeight / totalHeight) * trackHeight); var maxThumbTop = trackHeight - thumbHeight; var maxScroll = totalHeight - viewHeight; var thumbTop = maxScroll > 0 ? (container.scrollTop / maxScroll) * maxThumbTop : 0; thumb.style.height = thumbHeight + 'px'; thumb.style.top = thumbTop + 'px'; } </script> </body> </html>